<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Cooked mode demo: type something and press Enter&quot;</span><span style="color:#9399B2;">);</span></span>
