<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Terminal restored to normal mode.&quot;</span><span style="color:#9399B2;">);</span></span>
